async (params, browser) => {
  // Open Notion database
  await browser.open(`${params.database_url}`)

  // Wait for database view
  await browser.waitForSelector('.notion-table-view, .notion-board-view, .notion-list-view, .notion-collection_view-block', 15000)

  // Let database render
  await browser.wait(3000)

  // Extract database rows from DOM
  const result = await browser.evaluate(`const headers = []; document.querySelectorAll('.notion-table-view-header-cell, .notion-collection-column-header').forEach(h => { headers.push(h.textContent?.trim() || ''); }); const rows = []; const rowEls = document.querySelectorAll('.notion-table-view .notion-collection-item, .notion-table-row, .notion-list-item'); for (let i = 0; i < Math.min(rowEls.length, 50); i++) { const row = rowEls[i]; const cells = row.querySelectorAll('.notion-table-view-cell, .notion-collection-property-value, td'); const rowData = {}; cells.forEach((cell, idx) => { const key = headers[idx] || 'col_' + idx; rowData[key] = cell.textContent?.trim()?.substring(0, 200) || ''; }); if (Object.values(rowData).some(v => v)) rows.push(rowData); } return { headers: headers, row_count: rows.length, rows: rows }`)

  return result
}
